INSERT INTO seo (id, article_id, yoast_tag_data) VALUES('7622', '7622', '{"_yoast_wpseo_metadesc": "This podcast is a way for me to better connect with my friends — get to know them on a more personal level, share stories, and find similarities. During the show, we drink a few glasses of whatever the guest prefers (most of the time it is wine) and we just vibe out. This show is nothing fancy or out of the ordinary. Just two friends, drinking and having conversation. The first person that came to mind when I first started this show was Liz Pham. We discuss our similaar backgrounds, her academic career, toxic masculinity and more!", "_yoast_wpseo_primary_category": "16794"}');
INSERT INTO seo (id, article_id, yoast_tag_data) VALUES('7623', '7623', '{}');
