INSERT INTO seo (id, article_id, yoast_tag_data) VALUES('7629', '7629', '{}');
INSERT INTO seo (id, article_id, yoast_tag_data) VALUES('7630', '7630', '{"_yoast_wpseo_primary_category": "16794", "_yoast_wpseo_metadesc": "For my second guest this week, I have my very good friend and podcast editor, Maddie Avarese. In this episode, which is filled with shameless name-drops and shout-outs, Maddie explains to me the basis of astrology and accepts me, despite the fact that I am a moody Scorpio. (Just kidding...or am I?) Continuing on, we discuss the battle of embracing your personal brand without linking it to your professional persona, as well as feeling comfortable in your own skin. We’ve all been there, am I right? This episode addresses many things that people may be scared to discuss, but that’s okay"}');
