INSERT INTO seo (id, article_id, yoast_tag_data) VALUES('7634', '7634', '{"_yoast_wpseo_metadesc": "This past week, Mark and Jair discussed what''s happening in the Eastern Conference Finals in the NBA, Major League Baseball, the wrapping up their regular season, and it’s eye-opening how the season is ending. They also discuss the many injuries currently happening in the NFL.", "_yoast_wpseo_primary_category": "16794"}');
