INSERT INTO seo (id, article_id, yoast_tag_data) VALUES('7640', '7640', '{"_yoast_wpseo_metadesc": "I promise you this is episode will make you think, laugh, and smile. At the end of the day that is all, I aim for. If I can make at least one person do all three of these things, then that means I’m doing my job as a “podcaster,” right. When it comes down to it, this world is far too crazy for you not to just sit back, check out, and listen to something that makes you feel less alone. In the words of the late and great Mac Miller, this episode had me “cheesin’ from cheek to cheek.” I hope it does the same thing for each and every one of my listeners. You all mean the world to me and I cannot wait for you all to hear the upcoming content we have in store for you.", "_yoast_wpseo_primary_category": "17779"}');
