INSERT INTO seo (id, article_id, yoast_tag_data) VALUES('7656', '7656', '{"_yoast_wpseo_metadesc": "In this episode, Liz came over so we could bake macaroons for a side project that we were working on together. In between mimosas and baking, we decided to record a podcast, haha! We first analyze the results of our Myers-Briggs Tests and discuss the stigmas the come with our astrological signs and talked about the trials and tribulations of maintaining trust and effective communication in a relationship and the toxicity of long-term relationships. We talked so much that we had to cut this into two episodes!", "_yoast_wpseo_primary_category": "16794"}');
