INSERT INTO seo (id, article_id, yoast_tag_data) VALUES('7678', '7678', '{"_yoast_wpseo_primary_category": "16794", "_yoast_wpseo_metadesc": "Last week was a very ‘Brandon and his mental health’ oriented episode. This week, we take a deeper dive into Liz’s experience with mental health. We discuss the feeling of being a burden on those around us, what it is like to be overworked and why we always seem to push ourselves to the brink of exhaustion. We also talk about close friendships, growing from traumatic experiences, and parental sacrifices."}');
INSERT INTO seo (id, article_id, yoast_tag_data) VALUES('7679', '7679', '{"_yoast_wpseo_metadesc": "This past week, Mark and Jair discussed the first Game of the World Series between the Tampa Bay Rays and Los Angeles Dodgers. Both hosts noticed how well Mookie Betts has done defensively throughout the postseason. Both hosts also detailed who they are rooting for personally. Currently, the series is tied 1-1 and both the Rays and Dodgers are at the neutral site in Arlington, Texas. However, for the next three games, the Rays will serve as the home team.", "_yoast_wpseo_primary_category": "16794"}');
