INSERT INTO seo (id, article_id, yoast_tag_data) VALUES('7690', '7690', '{"_yoast_wpseo_metadesc": "Thank you so much for coming back! You all are awesome in every way, and we are so grateful for every last one of you. This week, we touched on our dreams. Not the “I wanna be a billionaire so freaking bad” kind of dream, but the “oh my god why am I naked in the middle of my COM Theory class?” kind of dream. We also talk about some crazy lucid dreams, some of which involve eating soap to try to wake up. This is a very interesting episode filled with lots of “WTF” moments, and you will not want to miss this. Don''t forget that no matter how bad a dream feels, when you open your eyes you''ll realize “it was only just a dream.”", "_yoast_wpseo_primary_category": "16794"}');
INSERT INTO seo (id, article_id, yoast_tag_data) VALUES('7691', '7691', '{"_yoast_wpseo_primary_category": "16794", "_yoast_wpseo_metadesc": "This past week, Mark and Jair discussed the outcome of the World Series after the Dodgers defeated the Rays in six games. Corey Seager won World Series MVP in the triumph that ended the 32-year championship drought for the Dodgers. They add another reason for the city of Los Angeles to celebrate."}');
