INSERT INTO seo (id, article_id, yoast_tag_data) VALUES('7712', '7712', '{"_yoast_wpseo_primary_category": "16794", "_yoast_wpseo_metadesc": "In this episode, we get straight to the point and address some of the horror stories that Liz and I have faced growing up as minorities in predominantly white hometowns. These stories range from heated encounters in parking lots to maintaining an unwanted persona in the classroom. We also have an interesting discussion about the difference between ignorance and hate. It is important to understand the difference between the two. Moving on, we shift to the importance family plays in Southeast Asian cultures."}');
