INSERT INTO seo (id, article_id, yoast_tag_data) VALUES('7727', '7727', '{"_yoast_wpseo_metadesc": "This episode answers the age-old question “what does the opposite sex think.” You must believe me when I say this was a very entertaining episode to do. We took questions from you, our followers, as well as questions that we made up on our own. Questions ranged from as simple as “why do guys hock loogies?” to as thought-provoking as “do girls hate falling in love with the wrong person as much as guys do?”", "_yoast_wpseo_primary_category": "16794"}');
