INSERT INTO seo (id, article_id, yoast_tag_data) VALUES('7746', '7746', '{"_yoast_wpseo_metadesc": "This episode starts with even more tea spillage about questions for the opposite sex. However, it would not be a Liz and Brandon episode if we didn’t talk about mental health. In this part, we get a little deeper, delving into the effects of gender stereotypes and how they affect our behaviors. (WARNING: some tears may have been shed). Again, I want to put a disclaimer out there: all of our answers, opinions, and experiences are our own and don’t generalize to our genders.", "_yoast_wpseo_primary_category": "16794"}');
INSERT INTO seo (id, article_id, yoast_tag_data) VALUES('7747', '7747', '{"_yoast_wpseo_metadesc": "Mark and Jair Explain the major happenings that went down this week in sports. From the NBA Draft to COVID in MLB to the Giants. Tune in to hear all about it and get your weekly update and breakdown.", "_yoast_wpseo_primary_category": "16794"}');
