INSERT INTO seo (id, article_id, yoast_tag_data) VALUES('7753', '7753', '{"_yoast_wpseo_metadesc": "This will be our last episode of the season but don''t worry, we’ll be back in the winter! In this episode, we go straight for the heartstrings. How so? Well, we write letters to our exes and read them to you all. THE TEA! Brandon writes one to his ex-girlfriend while Liz writes one to an ex-girl-friend (platonic). Full disclosure, these letters are not damning in any way but rather an expression of what we learned from these relationships and how we have grown as individuals since then.", "_yoast_wpseo_primary_category": "17779"}');
