INSERT INTO seo (id, article_id, yoast_tag_data) VALUES('7789', '7789', '{"_yoast_wpseo_metadesc": "The episodes for this week and the next will be very “Brandon”-focused. As you listen this week, you will learn that Brandon has a very turbulent past with sobriety. This is something that he has discussed briefly before, but in today’s episode, he tells his full story of struggle, determination and recovery.", "_yoast_wpseo_primary_category": "16794"}');
