INSERT INTO seo (id, article_id, yoast_tag_data) VALUES('7865', '7865', '{"_yoast_wpseo_metadesc": "In this episode we get to know Alex Jenkins, the father, gamer and life-long dragon. We get a glimpse of his #COVIDLife as a professor and a parent, which includes rocking a luscious beard that we wish you all could see. Huge kudos to Jenkins for being the best dad to his two kids during these times, while Brandon and I are here barely being able to take care of ourselves.", "_yoast_wpseo_primary_category": "16794"}');
