INSERT INTO seo (id, article_id, yoast_tag_data) VALUES('7925', '7925', '{"_yoast_wpseo_metadesc": "In this episode, Chris and Lena take a look at Ghost World, the 2001 film starring Thora Birch, Scarlett Johansson, and of course, Steve Buscemi. They cast their guesses on what happens in the film and compare it with what actually does. After a few guessing games and discussing the plot, Chris and Lena discuss what they liked and didn''t like about the film.", "_yoast_wpseo_estimated-reading-time-minutes": "2", "_yoast_wpseo_primary_category": "16794"}');
INSERT INTO seo (id, article_id, yoast_tag_data) VALUES('7926', '7926', '{"_yoast_wpseo_metadesc": "In this episode, Brandon and Liz give you their inside experience from when they went to a psychic and you get to hear all the juicy details that come from that! They also go off on a slight tangent towards the end about love and roommates...but what else is new?", "_yoast_wpseo_estimated-reading-time-minutes": "2", "_yoast_wpseo_primary_category": "16794"}');
INSERT INTO seo (id, article_id, yoast_tag_data) VALUES('7927', '7927', '{"_yoast_wpseo_metadesc": "This week, Gary and I finish our conversation about the Netflix movies coming out through the end of 2020. From there we touch on all of the release date shifts of various movies, especially what it means for Marvel''s fourth phase.", "_yoast_wpseo_estimated-reading-time-minutes": "2", "_yoast_wpseo_primary_category": "16794"}');
