INSERT INTO seo (id, article_id, yoast_tag_data) VALUES('7949', '7949', '{"_yoast_wpseo_metadesc": "Liz and Brandon''s good friends Ashley and Dice sit down with them to talk everything from brand ambassadorship to our hectic lives. this episode is filled with chaotic good energy, so we hope you enjoy!", "_yoast_wpseo_estimated-reading-time-minutes": "1", "_yoast_wpseo_primary_category": "16794"}');
INSERT INTO seo (id, article_id, yoast_tag_data) VALUES('7950', '7950', '{"_yoast_wpseo_metadesc": "In this episode, Chris and Lena watch the 1986 film \\"Parting Glances\\". As usual, guesses are made about the film''s plot and Steve''s role and are compared with what actually happens in the film. Chris and Lena found the film to be a bit underwhelming, but had much to say regardless. Enjoy!", "_yoast_wpseo_estimated-reading-time-minutes": "2", "_yoast_wpseo_primary_category": "16794"}');
INSERT INTO seo (id, article_id, yoast_tag_data) VALUES('7951', '7951', '{"_yoast_wpseo_primary_category": "16794", "_yoast_wpseo_metadesc": "This past week Mark and Jair discussed the play of the New York Yankees. What do they need to do in order to get rolling on the season? In the National League East, Mark feels as if the Phillies need to make a trade for another starter. Both Mark and Jair discussed what’s going on in the NBA. How will the Knicks do in NBA Free Agency? Are they now officially a destination that Free Agents may want to go to? How do they compare to the Brooklyn Nets? Should people be concerned on the Portland Trail Blazers? How are the Atlanta Hawks doing?The NFL Draft is coming up. Be sure to take a look at it.", "_yoast_wpseo_estimated-reading-time-minutes": "1"}');
INSERT INTO seo (id, article_id, yoast_tag_data) VALUES('7952', '7952', '{"_yoast_wpseo_primary_category": "16794", "_yoast_wpseo_metadesc": "Liz and Brandon sit down with the President of Drexel University, Mr. John Fry. This is the first true \\"interview style\\" Brandon and Liz have ever done. We learn many things, but above all, we learn that President Fry is just like everyone else. He is just... John. Enjoy the listen.", "_yoast_wpseo_estimated-reading-time-minutes": "2"}');
